class Solution:
    def findLUSlength(self, strs):
        def is_subseq(s, t):
            it = iter(t)
            return all(c in it for c in s)
        best = -1
        for i, s in enumerate(strs):
            ok = True
            for j, t in enumerate(strs):
                if i != j and is_subseq(s, t):
                    ok = False
                    break
            if ok and len(s) > best:
                best = len(s)
        return best

