class Solution:
    def findLUSlength(self, strs):
        def sub(a, b):
            i = 0
            for ch in b:
                if i < len(a) and a[i] == ch:
                    i += 1
            return i == len(a)
        best = -1
        for i in range(len(strs)):
            if all(i == j or not sub(strs[i], strs[j]) for j in range(len(strs))):
                best = max(best, len(strs[i]))
        return best

