var findLUSlength = function(strs) {
    const sub = (a, b) => {
        let i = 0;
        for (const ch of b) {
            if (i < a.length && a[i] === ch) i++;
        }
        return i === a.length;
    };
    let best = -1;
    for (let i = 0; i < strs.length; i++) {
        let ok = true;
        for (let j = 0; j < strs.length; j++) {
            if (i !== j && sub(strs[i], strs[j])) { ok = false; break; }
        }
        if (ok) best = Math.max(best, strs[i].length);
    }
    return best;
};
